import{_ as t,c as a,o as e,V as l}from"./chunks/framework.9b555ede.js";const T=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note/Http协议的研究.md","filePath":"note/Http协议的研究.md","lastUpdated":1645753949000}'),i={name:"note/Http协议的研究.md"},o=l('<h3 id="http1-0" tabindex="-1">HTTP1.0 <a class="header-anchor" href="#http1-0" aria-label="Permalink to &quot;HTTP1.0&quot;">​</a></h3><ul><li><p>只能与服务器保持短暂的连接，每次请求都需要与服务器建立一个 TCP 连接，完成后会立即断开</p></li><li><p>对头阻塞，下一个请求必须在前一个请求响应到达后才能发送</p></li></ul><h3 id="http1-1" tabindex="-1">HTTP1.1 <a class="header-anchor" href="#http1-1" aria-label="Permalink to &quot;HTTP1.1&quot;">​</a></h3><ul><li>支持长连接， 增加了一个 Connection：keep-Alive 连接可复用</li><li>请求管道化，实际使用起来存在各种各样的问题，因此很多浏览器都没支持这个特性</li><li>我们平时看到的并行加载，其实是浏览器为了提高资源加载效率，在同域名下开启了 6-8 个 tcp 连接进行并行下载。</li><li>缓存处理机制，（强缓存和协商缓存）</li><li>支持断点传输</li><li>增加了 host 字段，使得同一台服务器能够用来创建多个 web 站点</li></ul><h3 id="http2-0" tabindex="-1">HTTP2.0 <a class="header-anchor" href="#http2-0" aria-label="Permalink to &quot;HTTP2.0&quot;">​</a></h3><ul><li>支持并发，多路复用</li><li>头部压缩</li><li>服务器主动推送，无需客户端明确的请求</li></ul><h3 id="浏览器的缓存策略" tabindex="-1">浏览器的缓存策略 <a class="header-anchor" href="#浏览器的缓存策略" aria-label="Permalink to &quot;浏览器的缓存策略&quot;">​</a></h3><p>浏览器缓存分为本地缓存（强缓存），协商缓存（再验证）两个阶段</p><p>本地缓存，以资源的 url 为唯一索引，在用户第一次访问资源时，浏览器会将符合条件的文件添加到缓存池中。浏览器会优先从缓存池中检索，如果命中，则直接使用，否则从服务器上请求该文件。</p><p>cache-control (首部)</p><ul><li>no-store 不存储，即响应会禁止缓存对响应的拷贝</li><li>no-cache 响应可以存储，但在与服务器进行新鲜度再验证之前，该缓存不能提供给客户端使用</li><li>max-age 表示从响应回来时开始计数 must-revalidate 必须进行新鲜度验证，在没有进行再验证的情况下，不能使用已过期的副本缓存。</li></ul><p>协商缓存，当缓存文件到达缓存期限时，如果此时用户再次发起请求，但该文件其实并未发生变化，由于期限已到，不得不重写请求服务器，这样就造成了资源浪费，我们对这个阶段进行的优化操作，就称之为协商缓存。</p><ul><li>If-Modified-Since:&lt; date &gt; 如果从指定日期之后文档被修改过了，就执行请求的方法获取新的内容。与服务器响应首部 Last-Modified 配合使用。</li><li>If-None-Match: ETag 服务器可以为文档提供特殊的标签（ETag），而不是将其与最近修改日期相匹配，这些标签就像序列号一样。如果已缓存标签与服务器文档中的标签有所不同，If-None-Match 首部就会执行请求的方法，获取新的内容。与服务器响应首部 ETag 配合使用。</li></ul>',13),r=[o];function n(c,h,p,s,d,_){return e(),a("div",null,r)}const f=t(i,[["render",n]]);export{T as __pageData,f as default};
